      /* ---- about page ---- */
      about_why_h2: 'Tại sao Cần Tái cơ cấu Ngay Bây giờ?<small>Tại sao Bây giờ?</small>',
      issue1_h: 'Vấn đề 1: Trẻ em giảm nhanh chóng',
      issue1_p: 'Tính đến năm 2025, dân số từ 19 tuổi trở xuống tại khu vực Shinooka đã giảm xuống còn <strong>chưa đến một nửa so với 20 năm trước</strong>. Trong khi đó, dân số từ 65 tuổi trở lên <strong>tăng khoảng 2,5 lần</strong>.',
      issue2_h: 'Vấn đề 2: Cơ sở vật chất xuống cấp',
      issue2_p: 'Trường Tiểu học Shinooka được xây dựng vào năm <strong>1958 (hơn 60 năm trước)</strong>, và Trường THCS Shinooka được xây dựng vào năm <strong>1965 (khoảng 60 năm trước)</strong>. Các trường khác cũng đang xuống cấp tương tự.',
      issue3_h: 'Vấn đề 3: Xu hướng mỗi khối chỉ còn một lớp',
      issue3_p: 'Nếu xu hướng hiện tại tiếp tục, <strong>đến năm 2033, tất cả các trường tiểu học và THCS Shinooka trong khu vực Shinooka dự kiến chỉ còn một lớp mỗi khối</strong>.',
      stat_over_20y: 'trong 20 năm',
      stat_youth_label: 'Thay đổi dân số dưới 19 tuổi',
      stat_senior_label: 'Thay đổi dân số trên 65 tuổi',
      stat_class_label: 'Tất cả tiểu học &amp; THCS Shinooka dự kiến<br>có 1 lớp mỗi khối',
      stat_reorg_label: 'Tái cơ cấu Giai đoạn 1 (Đã lên kế hoạch)',
      about_city_view: '<strong>Quan điểm của thành phố:</strong> "Trước tình trạng học sinh ngày càng giảm, không thể trì hoãn việc tái cơ cấu trường học — cần tiến hành càng sớm càng tốt." (Ban Giáo dục Thành phố Komaki)',
      about_plan_h2: 'Kế hoạch Tái cơ cấu Giai đoạn 1<small>Phase 1 Reorganization Plan</small>',
      about_plan_intro: 'Năm học 2027, <strong>5 trường tiểu học và 3 trường THCS</strong> hiện tại sẽ được tái cơ cấu thành <strong>2 trường tiểu học và 2 trường THCS</strong>. Các trường được chia thành nhóm "Đông" (Tokadai Higashi) và "Tây" (Tokadai Nishi).',
      about_elem_h3: '■ Tái cơ cấu Trường Tiểu học',
      about_jhs_h3: '■ Tái cơ cấu Trường THCS',
      th_new_name: 'Tên trường mới',
      th_merged: 'Các trường được hợp nhất',
      th_note: 'Ghi chú',
      about_oshiro_box: '<strong>Về Khu vực Trường Tiểu học Oshiro:</strong> Khu vực Oshiro được chia thành hai. Khu vực Okusa/Shiroyama 3-chome sẽ hợp nhất vào Trường Tiểu học Tokadai Higashi, trong khi khu vực Shiroyama 2, 4 và 5-chome sẽ hợp nhất vào Trường Tiểu học Tokadai Nishi. Đối với Shiroyama 3 và 4-chome, một cuộc họp cộng đồng đã được tổ chức vào ngày 27 tháng 7 năm 2025 và khảo sát cư dân được thực hiện trước khi xác định ranh giới khu vực.',
      about_diagram_h3: '■ Sơ đồ Tái cơ cấu',
      group_east: 'Nhóm Đông',
      group_west: 'Nhóm Tây',
      about_schools_h2: 'Vị trí Trường học<small>School Locations</small>',
      about_mapnote_p: 'Bản đồ bên dưới hiển thị khu vực Shinooka. Nhấp vào tên từng trường để xem vị trí trên Google Maps.',
      about_map_before_h4: '📚 Trường học hiện tại (Trước tái cơ cấu)',
      about_map_after_h4: '🏫 Trường học mới (từ năm học 2027)',
      about_map_note: '※ 4 trường mới sẽ sử dụng tòa nhà hiện có của các trường cùng tên.',
      about_commute_h2: 'Kế hoạch Đi học<small>Commuting Plan</small>',
      transport_elem_h: 'Học sinh Tiểu học: Xe buýt trường',
      transport_elem_p: '<strong>Dịch vụ xe buýt trường đang được giới thiệu</strong> cho học sinh tiểu học.<br><br>· <strong>Tuyến buổi sáng:</strong> 1 chuyến<br>· <strong>Tuyến buổi chiều:</strong> Tối đa 3 chuyến (vào các ngày có hoạt động câu lạc bộ)<br>· <strong>Chi phí: Thành phố chi trả toàn bộ (miễn phí cho học sinh)</strong><br><br>Điểm dừng xe buýt và lịch trình sẽ được xác định sau khi phối hợp với các trường và đơn vị vận hành.',
      transport_jhs_h: 'Học sinh THCS: Đi xe đạp',
      transport_jhs_p: '<strong>Đi xe đạp</strong> được lên kế hoạch cho học sinh THCS.<br><br>Chi tiết về tuyến đường đi học an toàn và cách xử lý vào ngày mưa sẽ được nghiên cứu và công bố sau.',
      about_phase2_h2: 'Về Tái cơ cấu Giai đoạn 2<small>Phase 2 (Future)</small>',
      about_phase2_box: '<strong>Triển vọng sau Giai đoạn 1:</strong> Nếu số học sinh tiếp tục giảm sau Giai đoạn 1 (năm học 2027), có thể xem xét hợp nhất thêm thành <strong>1 trường tiểu học và 1 trường THCS</strong>, cùng với việc giới thiệu <strong>giáo dục tích hợp tiểu học-THCS</strong>. Quyết định về Giai đoạn 2 sẽ được đưa ra dựa trên tình hình sau Giai đoạn 1.',
      about_buildings_h2: 'Về Cơ sở vật chất Trường đóng cửa<small>Closed School Buildings</small>',
      building_h: 'Tòa nhà trường học',
      building_p: 'Các tòa nhà của trường đóng cửa <strong>nhìn chung dự kiến sẽ bị phá dỡ</strong>.',
      gym_h: 'Nhà thể chất &amp; Sân trường',
      gym_p: 'Nhà thể chất và sân trường <strong>nhìn chung dự kiến sẽ được giữ lại</strong>. Chúng được kỳ vọng sẽ được sử dụng cho các hoạt động thể thao và cộng đồng địa phương.',
      about_process_h2: 'Quy trình Ra quyết định<small>Decision-Making Process</small>',
