      map_h4_new4: '🏫 4 Trường mới (từ năm học 2027)',
      map_before_h2: 'Vị trí Trường học Hiện tại<small>Current School Locations</small>',
      map_before_p: 'Vị trí của 8 trường hiện tại phục vụ đến tháng 3/2027. Điểm đến hợp nhất được hiển thị theo nhóm Đông/Tây. Nhấp vào tên từng trường để xem vị trí trên Google Maps.',
      map_h4_elem: '📚 Trường Tiểu học (5 trường)',
      map_h4_jhs: '🏫 Trường THCS (3 trường)',
      merge_east_elem: '→ Hợp nhất vào Trường TH Tokadai Higashi',
