      faq_contact_tel_label: 'Teléfono',
      faq_contact_web_label: 'Sitio Web Oficial',
      /* ---- council ---- */
      council_source_intro: '<strong>Fuente:</strong> Basado en el Boletín del Consejo Municipal de Komaki N.° 214 (publicado en mayo de 2026). Por favor, consulte el Boletín N.° 214 para obtener información oficial precisa.',
      council_overview_title: '📋 1.ª Sesión Ordinaria de 2026 – Resumen',
